<template><div class="app"><component :is="page"/><BottomNav v-if="showBottomNav"/></div></template><script setup lang="ts">import{computed,h}from'vue';import{route,showBottomNav}from'./router';import BottomNav from'./components/BottomNav.vue';import HomePage from'./pages/HomePage.vue';import MessagesPage from'./pages/MessagesPage.vue';import MessageDetailPage from'./pages/MessageDetailPage.vue';import DataPage from'./pages/DataPage.vue';const pages:any={orders:'订单',products:'商品',finance:'财务',settings:'设置'};const page=computed(()=>{if(route.value.path==='/')return HomePage;if(route.value.path==='/messages')return MessagesPage;if(route.value.chatId)return MessageDetailPage;const k=route.value.path.split('/')[1];return{render:()=>h(DataPage,{kind:k,title:pages[k]||'页面'})}})</script>